import{_ as t,c as o,o as n,ag as s}from"./chunks/framework.Bw-5EFTY.js";const h=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md"}'),a={name:"guide/architecture.md"};function r(d,e,i,c,l,p){return n(),o("div",null,e[0]||(e[0]=[s(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="layer-structure" tabindex="-1">Layer Structure <a class="header-anchor" href="#layer-structure" aria-label="Permalink to &quot;Layer Structure&quot;">​</a></h2><p>Robota SDK follows a strict bottom-up layered assembly model. Each layer builds on the layer below.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>agent-cli         ← UI layer: Ink TUI, slash commands, permission prompts</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>agent-sdk         ← Assembly layer: config, context, session factory, query()</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>agent-sessions    ← Session lifecycle: permissions, hooks, compaction, persistence</span></span>
<span class="line"><span>agent-tools       ← Tool infrastructure + 8 built-in CLI tools</span></span>
<span class="line"><span>agent-providers   ← AI provider implementations (Anthropic, OpenAI, Google)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>agent-core        ← Foundation: Robota engine, abstractions, DI, events, plugins</span></span></code></pre></div><h2 id="package-roles" tabindex="-1">Package Roles <a class="header-anchor" href="#package-roles" aria-label="Permalink to &quot;Package Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Package</th><th>Role</th><th>Layer</th></tr></thead><tbody><tr><td><strong>agent-core</strong></td><td>Robota engine, execution loop, provider abstraction, permissions, hooks, plugin system</td><td>Foundation</td></tr><tr><td><strong>agent-tools</strong></td><td>ToolRegistry, FunctionTool, createZodFunctionTool, 8 built-in CLI tools</td><td>General</td></tr><tr><td><strong>agent-sessions</strong></td><td>Session class with permission enforcement, context tracking, compaction</td><td>General</td></tr><tr><td><strong>agent-providers</strong></td><td>AnthropicProvider, OpenAIProvider, GoogleProvider</td><td>General</td></tr><tr><td><strong>agent-sdk</strong></td><td>Assembly: config loading, context discovery, system prompt, createSession, query()</td><td>SDK-specific</td></tr><tr><td><strong>agent-cli</strong></td><td>Ink TUI: conversation UI, slash commands, permission prompts</td><td>CLI-specific</td></tr></tbody></table><h2 id="dependency-flow" tabindex="-1">Dependency Flow <a class="header-anchor" href="#dependency-flow" aria-label="Permalink to &quot;Dependency Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>agent-cli ─→ agent-sdk ─→ agent-sessions ─→ agent-core</span></span>
<span class="line"><span>  │            ├─→ agent-tools ────────────→ agent-core</span></span>
<span class="line"><span>  │            ├─→ agent-provider-anthropic → agent-core</span></span>
<span class="line"><span>  │            └─────────────────────────→ agent-core  (types, permissions, hooks)</span></span>
<span class="line"><span>  └──────────────────────────────────────→ agent-core  (types only)</span></span></code></pre></div><p>Rules:</p><ul><li>Dependencies are one-way. No cycles.</li><li><code>agent-core</code> has zero workspace dependencies (foundation).</li><li><code>agent-sessions</code> depends only on <code>agent-core</code> (generic — no tools or providers).</li><li>Assembly (wiring tools + provider + prompt) happens in <code>agent-sdk</code>.</li></ul><h2 id="design-patterns" tabindex="-1">Design Patterns <a class="header-anchor" href="#design-patterns" aria-label="Permalink to &quot;Design Patterns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pattern</th><th>Where</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Facade</strong></td><td><code>Robota</code>, <code>Session</code></td><td>Single entry point hiding internal complexity</td></tr><tr><td><strong>Decorator</strong></td><td><code>PermissionEnforcer.wrapTools()</code></td><td>Wraps tools with permission checks</td></tr><tr><td><strong>Strategy</strong></td><td><code>IAIProvider</code>, <code>ISessionLogger</code></td><td>Swappable implementations</td></tr><tr><td><strong>Factory</strong></td><td><code>createSession()</code>, <code>createZodFunctionTool()</code></td><td>Object creation</td></tr><tr><td><strong>Null Object</strong></td><td><code>SilentLogger</code>, <code>DefaultEventService</code></td><td>Safe no-op defaults</td></tr><tr><td><strong>Registry</strong></td><td><code>ToolRegistry</code></td><td>Central tool management</td></tr><tr><td><strong>Composition</strong></td><td><code>Session</code> → sub-components</td><td>Delegation over inheritance</td></tr></tbody></table><h2 id="session-sub-components" tabindex="-1">Session Sub-Components <a class="header-anchor" href="#session-sub-components" aria-label="Permalink to &quot;Session Sub-Components&quot;">​</a></h2><p><code>Session</code> delegates to focused sub-components:</p><table tabindex="0"><thead><tr><th>Component</th><th>Responsibility</th></tr></thead><tbody><tr><td><code>PermissionEnforcer</code></td><td>Tool wrapping, permission checks, hook execution, output truncation</td></tr><tr><td><code>ContextWindowTracker</code></td><td>Token usage tracking, auto-compact threshold</td></tr><tr><td><code>CompactionOrchestrator</code></td><td>Conversation summarization via LLM (PreCompact hook)</td></tr></tbody></table><h2 id="plugin-architecture" tabindex="-1">Plugin Architecture <a class="header-anchor" href="#plugin-architecture" aria-label="Permalink to &quot;Plugin Architecture&quot;">​</a></h2><p><code>agent-core</code> defines the <code>AbstractPlugin</code> base class. 8 plugin implementations have been extracted to separate <code>@robota-sdk/agent-plugin-*</code> packages to keep <code>agent-core</code> dependency-free. Only <code>EventEmitterPlugin</code> remains built-in.</p><p>Plugins integrate with the agent lifecycle via hooks: <code>beforeRun</code>, <code>afterRun</code>, <code>onError</code>, <code>onStreamChunk</code>, <code>beforeToolExecution</code>, <code>afterToolExecution</code>.</p><h2 id="changes-from-v2-0-0" tabindex="-1">Changes from v2.0.0 <a class="header-anchor" href="#changes-from-v2-0-0" aria-label="Permalink to &quot;Changes from v2.0.0&quot;">​</a></h2><p>In v2.0.0, <code>agent-core</code> contained everything: tools, plugins, session management. In v3.0.0:</p><ul><li><strong>Tools</strong> moved to <code>agent-tools</code> (FunctionTool, ToolRegistry, built-in tools)</li><li><strong>Plugins</strong> extracted to <code>agent-plugin-*</code> packages</li><li><strong>Session</strong> created as a new package (<code>agent-sessions</code>) with permission and hook support</li><li><strong>SDK</strong> created as a new assembly layer (<code>agent-sdk</code>) with config/context loading</li><li><strong>CLI</strong> created as a new terminal UI (<code>agent-cli</code>)</li><li><strong>Permissions</strong> and <strong>Hooks</strong> added to <code>agent-core</code> as general-purpose infrastructure</li></ul>`,21)]))}const u=t(a,[["render",r]]);export{h as __pageData,u as default};
